import { Component, signal, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormBuilder, FormGroup, Validators, ReactiveFormsModule } from '@angular/forms';
import { ResumeService } from '../../core/services/resume.service';
import { AnalysisResult } from '../../core/models/resume.model';
import { ScoreRingComponent } from '../../shared/components/score-ring/score-ring.component';

@Component({
  selector: 'app-analyzer',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule, ScoreRingComponent],
  templateUrl: './analyzer.component.html',
  styleUrl: './analyzer.component.scss'
})
export class AnalyzerComponent {
  private fb = inject(FormBuilder);
  private resumeService = inject(ResumeService);

  form: FormGroup;
  selectedFile = signal<File | null>(null);
  isDragging = signal(false);
  isLoading = signal(false);
  analysisResult = signal<AnalysisResult | null>(null);
  errorMessage = signal<string | null>(null);

  constructor() {
    this.form = this.fb.group({
      jobDescription: ['', [Validators.required, Validators.minLength(10)]]
    });
  }

  onDragOver(event: DragEvent) {
    event.preventDefault();
    event.stopPropagation();
    this.isDragging.set(true);
  }

  onDragLeave(event: DragEvent) {
    event.preventDefault();
    event.stopPropagation();
    this.isDragging.set(false);
  }

  onDrop(event: DragEvent) {
    event.preventDefault();
    event.stopPropagation();
    this.isDragging.set(false);

    const files = event.dataTransfer?.files;
    if (files && files.length > 0) {
      this.handleFile(files[0]);
    }
  }

  onFileSelected(event: Event) {
    const input = event.target as HTMLInputElement;
    if (input.files && input.files.length > 0) {
      this.handleFile(input.files[0]);
    }
  }

  handleFile(file: File) {
    if (file.type !== 'application/pdf') {
      this.errorMessage.set('Please upload a PDF file');
      return;
    }

    if (file.size > 5 * 1024 * 1024) {
      this.errorMessage.set('File size must be less than 5MB');
      return;
    }

    this.selectedFile.set(file);
    this.errorMessage.set(null);
  }

  removeFile() {
    this.selectedFile.set(null);
  }

  onSubmit() {
    if (this.form.invalid || !this.selectedFile()) {
      return;
    }

    this.isLoading.set(true);
    this.errorMessage.set(null);
    this.analysisResult.set(null);

    this.resumeService.analyzeResume(this.selectedFile()!, this.form.value.jobDescription)
      .subscribe({
        next: (result) => {
          this.analysisResult.set(result);
          this.isLoading.set(false);
        },
        error: (error) => {
          this.errorMessage.set(error.error?.message || 'Failed to analyze resume. Please try again.');
          this.isLoading.set(false);
        }
      });
  }

  getVerdictClass(verdict: string): string {
    const verdictMap: { [key: string]: string } = {
      'Strong Match': 'strong',
      'Good Match': 'good',
      'Partial Match': 'partial',
      'Weak Match': 'weak'
    };
    return verdictMap[verdict] || 'weak';
  }
}
<div class="analyzer-container">
  <div class="analyzer-layout">
    <!-- Upload Form -->
    <div class="upload-section">
      <h1 class="page-title">Resume Analyzer</h1>
      
      <form [formGroup]="form" (ngSubmit)="onSubmit()">
        <!-- File Upload Zone -->
        <div class="form-group">
          <label class="form-label">Upload Resume (PDF)</label>
          <div 
            class="dropzone"
            [class.dragging]="isDragging()"
            [class.has-file]="selectedFile()"
            (dragover)="onDragOver($event)"
            (dragleave)="onDragLeave($event)"
            (drop)="onDrop($event)"
            (click)="fileInput.click()"
          >
            <input 
              #fileInput
              type="file" 
              accept=".pdf"
              (change)="onFileSelected($event)"
              style="display: none"
            />
            
            <div *ngIf="!selectedFile()" class="dropzone-content">
              <svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
                <path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"></path>
                <polyline points="17 8 12 3 7 8"></polyline>
                <line x1="12" y1="3" x2="12" y2="15"></line>
              </svg>
              <p class="dropzone-text">Drag and drop your resume here</p>
              <p class="dropzone-subtext">or click to browse</p>
              <p class="dropzone-hint">PDF only, max 5MB</p>
            </div>
            
            <div *ngIf="selectedFile()" class="file-selected">
              <svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
                <path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"></path>
                <polyline points="14 2 14 8 20 8"></polyline>
              </svg>
              <div class="file-info">
                <p class="file-name">{{ selectedFile()!.name }}</p>
                <p class="file-size">{{ (selectedFile()!.size / 1024 / 1024).toFixed(2) }} MB</p>
              </div>
              <button type="button" class="remove-file-btn" (click)="removeFile(); $event.stopPropagation()">
                <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
                  <line x1="18" y1="6" x2="6" y2="18"></line>
                  <line x1="6" y1="6" x2="18" y2="18"></line>
                </svg>
              </button>
            </div>
          </div>
        </div>

        <!-- Job Description -->
        <div class="form-group">
          <label class="form-label" for="jobDescription">Job Description</label>
          <textarea 
            id="jobDescription"
            formControlName="jobDescription"
            class="form-textarea"
            placeholder="Paste the job description here..."
            rows="8"
          ></textarea>
          <div *ngIf="form.get('jobDescription')?.invalid && form.get('jobDescription')?.touched" class="form-error">
            Job description is required (minimum 10 characters)
          </div>
        </div>

        <!-- Error Message -->
        <div *ngIf="errorMessage()" class="error-alert">
          {{ errorMessage() }}
        </div>

        <!-- Submit Button -->
        <button 
          type="submit" 
          class="submit-btn"
          [disabled]="form.invalid || !selectedFile() || isLoading()"
        >
          <span *ngIf="!isLoading()">Analyze Resume</span>
          <span *ngIf="isLoading()" class="loading-content">
            <svg class="spinner" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
              <circle cx="12" cy="12" r="10"></circle>
            </svg>
            Analyzing...
          </span>
        </button>
      </form>
    </div>

    <!-- Results Section -->
    <div class="results-section" *ngIf="analysisResult()">
      <div class="result-card">
        <div class="score-section">
          <app-score-ring [score]="analysisResult()!.matchScore"></app-score-ring>
          <div class="verdict-badge" [ngClass]="getVerdictClass(analysisResult()!.verdict)">
            {{ analysisResult()!.verdict }}
          </div>
        </div>

        <div class="summary-section">
          <h3 class="section-title">Summary</h3>
          <p class="summary-text">{{ analysisResult()!.summary }}</p>
        </div>

        <div class="strengths-section">
          <h3 class="section-title">Strengths</h3>
          <ul class="strengths-list">
            <li *ngFor="let strength of analysisResult()!.strengths">
              <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">
                <polyline points="20 6 9 17 4 12"></polyline>
              </svg>
              {{ strength }}
            </li>
          </ul>
        </div>

        <div class="keywords-section">
          <h3 class="section-title">Missing Keywords</h3>
          <div class="keywords-list">
            <span *ngFor="let keyword of analysisResult()!.missingKeywords" class="keyword-badge">
              {{ keyword }}
            </span>
          </div>
        </div>

        <div class="suggestions-section">
          <h3 class="section-title">Suggestions for Improvement</h3>
          <div class="suggestion-card" *ngFor="let suggestion of analysisResult()!.suggestions">
            <h4 class="suggestion-section">{{ suggestion.section }}</h4>
            <div class="suggestion-before">
              <span class="suggestion-label">Before:</span>
              <p>{{ suggestion.original }}</p>
            </div>
            <div class="suggestion-after">
              <span class="suggestion-label">After:</span>
              <p>{{ suggestion.improved }}</p>
            </div>
          </div>
        </div>
      </div>
    </div>
  </div>
</div>
